-- W1.6 questions batch 4795/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-53250add-moex-00252', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'essay', '張三有子甲與女兒乙各一人。張三於罹癌入院後欲將所持有之 A地予以
出售，故簽署授權書，載明授權兒子甲代為出售A地，包含從契約訂定
到登記等事宜之各階段處理權及代理權。後來張三因癌症惡化於A地買
賣契約簽訂時，已經有意識狀態不清之情形，甲持其張三簽名之授權書，
與丙簽訂 A地買賣契約價金約定為 740萬元，並已給付由乙保管，由丙
依法辦理登記而於辦竣 A地登記前，張三因癌症過世。於張三死亡前，
均未曾受監護之宣告。
張三女兒乙認為張三授權甲之際已經病情嚴重而意識不清，主張該買賣
契約未有合法授權，故甲為無權代理，買賣契約無效，並主張甲保管 740
萬之行為侵害其財產繼承權，是否有理？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00253', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'essay', '兄弟姊妹甲、乙、丙、丁四人共有Ａ地，應有部分各四分之一，甲過世
後，由乙、丙、丁繼承甲之應有部分。嗣乙以丙、丁為被告提起分割共
有物訴訟，其主張將乙、丙、丁繼承甲之應有部分之公同共有分割為分
別共有，由乙、丙、丁各分得三分之一之應有部分，亦即甲之應有部分
由公同共有分割為分別共有後，由乙、丙、丁各享有十二分之一應有部
分，並與其原應有部分合併計算後，由乙、丙、丁以各應有部分三分之
一將Ａ土地均等 3 等份，由其等各單獨所有之，乙、丙、丁雖就分配位
置有不同意見，然均同意先就共同繼承甲之應有部分而終止公同共有關
係，並為分割，試問乙的分割方案是否有理？（20 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00254', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '胎兒甲是遺腹子，其父遭乙駕車不慎撞死。下列關於胎兒甲的權利之敘述，何者正確？', '["甲尚無權利能力，不得向乙主張權利", "關於甲權利之保護，甲視為有權利能力，然而他尚未出生，無法向乙請求損害賠償", "甲得以其母為法定代理人，向乙請求損害賠償", "無論甲將來是否為死產，其胎兒期間之權利不受影響 32820、33320 33520"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00255', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲公司於民國（下同）102年2月間舉辦員工旅遊，住宿乙之旅店，積欠住宿費新臺幣10萬元， 乙於103年2月催告後甲仍不給付，乙乃於104年2月訴請甲給付，於105年2月獲勝訴判決確 定。下列敘述，何者正確？', '["乙於103年2月催告時，時效中斷", "乙於104年2月訴請甲給付時，時效不完成", "判決確定後，時效重新起算5年", "判決確定後，時效重新起算15年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00256', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲擁有A鑽石，出租予乙使用，乙出賣並讓與予第三人丙。下列敘述，何者錯誤？', '["倘若丙為惡意，甲仍為鑽石之所有權人", "縱使丙為惡意，甲仍不得向丙請求返還鑽石", "倘若丙為善意且無重大過失，丙取得鑽石之所有權", "倘若丙為善意且無重大過失，甲得向乙請求損害賠償或利益之返還"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00257', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '下列關於民法法源之敘述，何者正確？', '["民法第1條所稱之習慣，僅指單純之習慣", "憲法總綱無法作為私法上具體請求權之基礎，故不得為法源", "法規命令非法律，故不得為法源", "法律精神演繹而出之一般法律原則，得為法源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00258', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲借給乙1千萬元，乙為避免甲強制執行其所有之A屋，乃與好友丙通謀虛偽作成買賣契約及A 屋之移轉登記。嗣後A屋被丁無權占有。下列敘述，何者錯誤？', '["乙丙間之買賣契約與物權行為均為無效", "乙得本於所有人之物上返還請求權，向丙請求塗銷所有權之登記", "甲於為保全對乙之借款返還請求權之情形下，其得以自己名義，代位乙對丙行使所有權之塗銷 登記", "丙得本於所有人之物上返還請求權，向丁請求返還A屋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00259', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '關於意思表示錯誤，下列何者為動機錯誤？', '["甲欲贈與A書給乙，而誤說為贈與B書", "甲向乙購屋，預期房屋大漲，但其後卻跌價", "甲告知秘書乙，向丙訂購A型機器，但乙口傳時誤為表示購買B型機器", "甲誤A犬為B犬向乙買受之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00260', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲向乙購買貨物一批，貨款總計新臺幣（下同）50萬元，下列情形，何者不會導致甲之50萬元 貨款債務消滅？', '["經乙之同意，甲交付等值之金塊給乙", "甲交付面額50萬元之即期支票給乙", "甲、乙同意將該買賣貨款更改為消費借貸", "甲要清償貨款債務時，因乙失蹤，甲乃向法院提存所為乙提存50萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00261', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲欲出租自己所有的A套房，於是刊登招租廣告，寫明A套房所在地點及每月租金數額，並附上 A套房內部清楚的照片。乙看到招租廣告後，立刻發電子郵件給甲表明願意依招租廣告上的條件 承租。下列關於甲乙間租賃關係是否成立之敘述，何者正確？', '["甲所為之招租廣告為要約，乙願意承租之意思表示為承諾，租賃關係成立", "甲所為之招租廣告與乙願意承租之意思表示為交錯要約，租賃關係成立", "甲所為之招租廣告為要約之引誘，乙願意承租之意思表示為要約，甲若承諾，則租賃關係成立", "甲所為之招租廣告為要約之引誘，乙願意承租之意思表示為要約，因內容一致，租賃關係成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL)
